export const gbActivities: Activity[] = [
  {"id":"gb-the-hat-game","title":"The Hat Game (Three-Round Guessing)","altNames":["Celebrity","Salad Bowl","Name Slips Game"],"type":"Game","place":"Inside","ageMin":9,"ageMax":15,"durationMin":45,"groupMin":6,"groupMax":24,"energy":2,"prep":"Low","blurb":"The same pile of name slips gets guessed three ways in a row, from full clues to a single word to total silence, and somehow the second round is always the funniest.","materials":["Paper, scrap slips (4-6 per player)","Pencils or pens, one per player","Container, bowl or hat","Timer or phone stopwatch"],"materialTags":["Paper","No materials"],"steps":["Hand each player 4-6 paper slips and have them write a well-known name, place, or thing on each, then fold and drop all slips into the hat.","Split into two teams sitting in a circle; a player from Team A draws slips and gives clues for 60 seconds while their team guesses, scoring one point per correct slip.","Used slips go in the team's pile; play passes around both teams until the hat is empty, then count Round 1 points and put ALL slips back.","Round 2: same slips, but the clue-giver may say only ONE word per slip; play through the whole hat again and tally.","Round 3: same slips again, but clues must be acted out silently (charades-style) with no words at all.","Add the three round scores; the team with the most total points wins, and read the funniest slips aloud."],"notes":"Cap names at things most of the group would know, or younger kids stall on Round 2. If two teams is unwieldy, run three smaller teams sharing one hat.","safety":"Keep pencils capped and pointed down when passing slips around a tight circle so no one is jabbed.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"How to Play Salad Bowl","url":"https://www.youtube.com/watch?v=t2VJ19f272Y"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/classroom-games/"}],"variations":["Round 4 'one sound' round where the clue is a single noise or gesture.","Theme the hat (only animals, only camp things) for a younger or topical group."],"subsets":[["Give shy writers example categories: a movie, an animal, a famous athlete."],["Demonstrate one round yourself so the clue rules are clear."],[],["Remind clue-givers the one word can be a synonym, not part of the answer."],[],[]]},
  {"id":"gb-wavelength-mind-meld","title":"Wavelength Spectrum Guess","altNames":["Wavelength","Dial Reading","Spectrum Game"],"type":"Game","place":"Inside","ageMin":10,"ageMax":16,"durationMin":30,"groupMin":4,"groupMax":16,"energy":1,"prep":"Low","blurb":"One player hides a target on a hot-cold-to-hot scale and gives a single clue, and the rest of the team argues their way toward exactly where that brain landed.","materials":["Paper, scrap for spectrum cards","Markers, assorted","Index cards or paper, for the dial pointer"],"materialTags":["Paper","Markers"],"steps":["Before camp or as a group, write a stack of two-ended scales on cards (Cold to Hot, Boring to Exciting, Underrated to Overrated, Scary to Cozy).","Draw a long spectrum line on a big sheet and lay a paper pointer that can slide along it; secretly one player ('the psychic') picks a hidden spot by pointing a slip face-down at one end.","The psychic flips a scale card, looks at where their hidden target sits, and says ONE clue word or phrase that fits that exact spot.","The rest of the team discusses and slides the pointer to where they think the hidden target is.","Reveal the hidden target: score 3 points for a bullseye region, 2 for close, 1 for near, 0 for a miss.","Rotate the psychic role each round; first team or player to a set score wins."],"notes":"Mixed-age groups love this because there is no single right answer, just persuasion. If kids freeze, pre-make 20 scale cards so no one waits on writing.","safety":"Keep the floor clear of the sliding pointer materials so no one slips stepping back to debate.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"How to Play Wavelength","url":"https://www.youtube.com/watch?v=CwL3Hzv0cQk"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/classroom-games/"}],"variations":["Two teams race: each guesses the same clue, closer team scores.","Lightning version with a 20-second discussion timer to keep energy up."],"subsets":[["Mix easy scales (Cold-Hot) with abstract ones (Underrated-Overrated)."],[],["Coach the psychic that a too-obvious clue helps the other team in versus mode."],[],[],[]]},
  {"id":"gb-taboo-forbidden-words","title":"Forbidden Words (Taboo-Style)","altNames":["Taboo","Don't Say It","Banned Word Game"],"type":"Game","place":"Inside","ageMin":10,"ageMax":16,"durationMin":30,"groupMin":4,"groupMax":20,"energy":2,"prep":"Medium","blurb":"Describe the secret word fast, but five obvious words are off-limits, so 'a four-legged barking pet' becomes a frantic test of your whole vocabulary.","materials":["Index cards or paper, one per word","Markers, assorted","Timer or phone stopwatch","Bell or noisemaker, optional"],"materialTags":["Paper","Markers"],"steps":["Make word cards: write a target word at the top and list five obvious 'forbidden' clue words below it (for DOG: pet, bark, puppy, tail, cat).","Form two teams; one clue-giver takes the deck and a teammate watches the card to catch forbidden words.","Start a 60-second timer; the giver describes the top word without saying it or any forbidden word, while their team shouts guesses.","On a correct guess, set the card aside (one point) and move to the next; if a forbidden word slips out, the watcher buzzes and that card is skipped.","When time runs out, count cards earned, then the other team takes a turn.","Play several rounds rotating clue-givers; highest total wins."],"notes":"Pre-make 30 plus cards so turns flow. Keep forbidden lists short for ages 9-10. The 'watcher' role keeps the non-active team engaged.","safety":"Remind kids guesses are shouted, not shoved forward; keep bodies seated so an excited team doesn't crowd the giver.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"How To Play: Taboo","url":"https://www.youtube.com/watch?v=1gYOWqx4WvI"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/classroom-games/"}],"variations":["Easier mode: only three forbidden words.","Solo-star mode where one giver describes for the whole room and everyone races to guess."],"subsets":[["Let kids help write cards as a warm-up; check the forbidden lists are fair."],["Pair a strong reader with a younger watcher."],[],["Decide in advance if 'sounds like' and gestures are allowed."],[],[]]},
  {"id":"gb-werd-association-chain","title":"Word Association Chain","altNames":["Free Association","One Word Links","Quick Link Game"],"type":"Game","place":"Both","ageMin":6,"ageMax":14,"durationMin":15,"groupMin":4,"groupMax":20,"energy":1,"prep":"None","blurb":"Sun, then beach, then ball, then dog, then leash, each player fires the first word the last one sparks, and the chain only breaks when someone hesitates.","materials":["No materials needed"],"materialTags":["No materials"],"steps":["Sit or stand in a circle and pick a starting player who says any word out loud.","The next player immediately says a single word that connects in any way to the one before.","Keep going around the circle, one connected word per person, with no repeats and a 3-second limit.","If a player hesitates too long, repeats a word, or says something clearly unconnected, they sit out (or the group simply restarts a new chain).","Play to see how long a chain the whole group can build, racing your own record."],"notes":"A perfect 5-minute filler for lining up or waiting. For little kids, drop the elimination and just celebrate long chains. Speed it up by going faster each lap.","safety":"If played walking in a line, have kids watch ahead so they don't bump the person in front while focused on the game.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"How to play Word Association","url":"https://www.youtube.com/watch?v=VFvryFlUGTM"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/classroom-games/"}],"variations":["Themed chains where every word must relate to the previous AND fit a category like food.","Backwards challenge: at the end, try to recite the whole chain in reverse."],"subsets":[[],["Model an obvious link, like 'milk' to 'cow', so the connection rule is clear."],[],[],["Track the record on a board to make the group competitive with itself."]]},
  {"id":"gb-i-spy-detective","title":"I Spy Mystery Object","altNames":["I Spy","Spy With My Little Eye","Find the Clue Object"],"type":"Game","place":"Both","ageMin":6,"ageMax":11,"durationMin":15,"groupMin":3,"groupMax":16,"energy":1,"prep":"None","blurb":"'I spy something green that the wind can move' sends every eye darting around the room until one sharp detective nails the hidden object.","materials":["No materials needed"],"materialTags":["No materials"],"steps":["The leader silently picks an object everyone can see in the room or area.","They give one clue about it, starting with a color: 'I spy with my little eye something blue.'","Players take turns guessing visible objects that match; the leader answers only 'yes' or 'no.'","If no one guesses, the leader adds a second clue (a shape, a use, or where it is) and guessing continues.","The player who guesses correctly becomes the next leader and picks a new secret object.","Play several rounds, encouraging trickier clues as kids warm up."],"notes":"Great for the youngest groups and for settling a room. To stretch it for older kids, require riddle-style clues instead of plain colors.","safety":"Keep guessers seated and pointing rather than running to touch objects across the room.","ages":["g13","g46"],"rating":0,"media":[{"title":"How to Play I Spy","url":"https://www.youtube.com/watch?v=5ybJXkE0VaY"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/classroom-games/"}],"variations":["Riddle I Spy where every clue must rhyme or be a riddle.","Category limit: the secret object must belong to a named group like 'things that hold water.'"],"subsets":[["For young kids, pick big obvious objects first."],[],["Remind the leader to answer honestly even when a wrong guess is close."],[],[],[]]},
  {"id":"gb-hangman-team-rescue","title":"Team Hangman Word Rescue","altNames":["Hangman","Guess the Letters","Word Gallows Lite"],"type":"Game","place":"Inside","ageMin":7,"ageMax":13,"durationMin":30,"groupMin":4,"groupMax":24,"energy":1,"prep":"Low","blurb":"Two teams race to crack the same hidden word letter by letter, building a happy little stick-figure friend instead of anything grim.","materials":["Whiteboard or large paper","Markers, assorted","Word list, prepared on slips"],"materialTags":["Paper","Markers"],"steps":["Draw a row of blanks for each letter of a secret word where everyone can see it.","Split into two teams that alternate guessing one letter at a time.","Correct letters get filled into every blank where they appear; the guessing team keeps the turn after a correct letter.","On a wrong letter, draw one piece of a friendly figure (a smiling explorer) and write the letter in a 'used' list so it isn't repeated.","A team may try to solve the whole word on its turn; a correct solve scores, a wrong solve passes the turn.","Finish the word before the figure is fully drawn; rotate who picks the next word."],"notes":"Use a rescue or build-up theme so it stays cheerful. Pick words at the group's reading level and keep a used-letter list to avoid arguments.","safety":"If kids come up to the board to write, set a one-at-a-time rule so no one collides reaching for the marker.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"How to Play Hangman","url":"https://www.youtube.com/watch?v=leW9ZotUVYo"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/classroom-games/"}],"variations":["Phrase mode with short camp sayings instead of single words.","Speed round: a 90-second timer to guess the whole word for bonus points."],"subsets":[["Pick words tied to the day's theme for extra fun."],[],[],["Draw an explorer or robot instead of a hangman so the theme is positive."],[],[]]},
  {"id":"gb-back-to-back-drawing","title":"Back-to-Back Drawing Telephone","altNames":["Telestrations","Drawphone","Describe and Draw"],"type":"Game","place":"Inside","ageMin":9,"ageMax":15,"durationMin":30,"groupMin":6,"groupMax":18,"energy":1,"prep":"Low","blurb":"You whisper a picture into words, the next person draws what they heard, and by the last hand the original 'cat in a hat' has become a glorious mystery.","materials":["Paper, several sheets per player","Pencils or pens, one per player","Word prompt slips, prepared"],"materialTags":["Paper","No materials"],"steps":["Give every player a small stack of paper and a pencil, seated in a circle or rows.","Each player secretly draws a prompt word from a pile and writes the word on their first page, then passes the stack to the left.","Now everyone draws a picture of the word they received on the next blank page, hides the written word, and passes again.","The next player looks only at the drawing, writes down what they think it is on a fresh page, hides the drawing, and passes.","Alternate drawing and guessing each pass until the stacks travel around; then open each stack and reveal the hilarious chain of word-to-picture-to-word.","Read the funniest transformations aloud as a group."],"notes":"Stick figures are encouraged; tell perfectionists it works BETTER when drawings are rough. With small groups, do fewer passes so chains still surprise.","safety":"Keep pencils capped or down when passing stacks across a circle so no one is poked.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"How to Play Telestrations","url":"https://www.youtube.com/watch?v=l2CMlfrx-q0"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/classroom-games/"}],"variations":["Caption-only round where players write a silly sentence instead of a single word.","Theme the prompts (movies, animals, camp moments) for a topical twist."],"subsets":[["Use simple, drawable prompts: 'surfing dog', 'angry pizza'."],[],["Remind players to fold or cover only the previous page, never peek further back."],[],[],[]]},
  {"id":"gb-twenty-one-questions-mystery","title":"Mystery Guest Interview","altNames":["What's My Line","Yes-No Interview","Secret Identity Quiz"],"type":"Game","place":"Inside","ageMin":10,"ageMax":16,"durationMin":30,"groupMin":5,"groupMax":20,"energy":1,"prep":"None","blurb":"A secret guest sits up front, and a panel of campers fires yes-or-no questions like real detectives until they unmask exactly who or what is sitting there.","materials":["Paper, scrap for secret identity slips","Pencils or pens"],"materialTags":["Paper","No materials"],"steps":["Write a stack of identity slips: famous people, jobs, or characters everyone knows (astronaut, soccer star, pirate, librarian).","One volunteer is the 'mystery guest' and secretly reads a slip without showing anyone.","The rest of the group is a detective panel that takes turns asking yes-or-no questions only ('Are you a real person?' 'Do you work outdoors?').","The guest answers only 'yes,' 'no,' or 'sometimes'; the panel may make a final guess on their turn instead of a question.","The panel wins if they identify the guest within a set number of questions; the guest wins if they stump the panel.","Rotate the mystery-guest role so everyone gets a turn in the hot seat."],"notes":"Differs from plain 20 Questions: the answerer ROLE-PLAYS the identity, so questions can be about their 'life.' Coach the panel to ask broad sorting questions first.","safety":"Keep the panel seated and taking turns by raised hand so the guest isn't overwhelmed by a shouting crowd.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"How to Play Who Am I Game","url":"https://www.youtube.com/watch?v=oI_jz2BVCro"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/classroom-games/"}],"variations":["Object mode where the secret is a thing instead of a person.","Two-guest version where the panel must figure out how the two secret identities are connected."],"subsets":[["Sort slips into easy and hard piles by age group."],[],["Suggest starter questions: living/fictional, real/imaginary, modern/historical."],[],[],[]]},
  {"id":"gb-rhyme-time-battle","title":"Rhyme Time Battle","altNames":["Rhyme Off","Last One Standing Rhymes","Word Tennis"],"type":"Game","place":"Both","ageMin":7,"ageMax":13,"durationMin":15,"groupMin":4,"groupMax":18,"energy":2,"prep":"None","blurb":"Someone shouts 'cat!' and the rhymes fly around the circle, hat, bat, mat, flat, until the well runs dry and the last rhymer claims the round.","materials":["No materials needed"],"materialTags":["No materials"],"steps":["Stand or sit in a circle; the leader calls out a simple starter word like 'play.'","Going around the circle, each player must say a real word that rhymes with the starter, with a 3-second limit.","No repeats; made-up words can be challenged and must be defended or dropped.","A player who can't rhyme in time, repeats, or gives a non-word sits out for the round.","When rhymes for that word are exhausted, the leader picks a new starter word and the circle plays again.","Last player standing wins the round, then a new round begins."],"notes":"Pick starter words with lots of rhymes (cat, day, light) for younger kids. To keep everyone in, play the no-elimination 'how many rhymes can we find' version.","safety":"If played standing, give each person enough elbow room so excited rhymers don't knock into neighbors.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"The Rhyming Words Game","url":"https://www.youtube.com/watch?v=3Cc1TL-0bXo"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/classroom-games/"}],"variations":["Category rhymes: the rhyme must also fit a theme (a rhyme that's also a food).","Two-word phrase challenge where players answer with rhyming pairs like 'big pig.'"],"subsets":[[],["Choose starter words ending in common sounds: -at, -ay, -ing."],["Have a tie-breaker judge ready for 'is that a real word' debates."],[],[],[]]},
  {"id":"gb-story-cubes-tale-spin","title":"Six-Word Story Spin","altNames":["Story Dice","Random Word Tale","Three Random Things"],"type":"Game","place":"Inside","ageMin":9,"ageMax":15,"durationMin":30,"groupMin":3,"groupMax":16,"energy":1,"prep":"Low","blurb":"Pull three random words from the bag, dragon, umbrella, sandwich, and you have ninety seconds to spin them into a story that has to make people gasp or laugh.","materials":["Paper, scrap for word slips","Markers or pens","Container, bag or bowl","Timer or phone stopwatch"],"materialTags":["Paper","Markers"],"steps":["As a group, write 30-plus random nouns on slips (objects, animals, places) and drop them in a bag.","On your turn, draw three slips without looking and read them aloud.","Take 30 seconds to think, then tell a short, made-up story (about a minute) that uses all three words naturally.","Listeners give a thumbs-up if all three words appeared and the story made sense or made them laugh.","Pass the bag to the next storyteller, who draws three fresh words.","Play in a circle so everyone tells at least one tale; vote on a favorite at the end."],"notes":"Great calm-down activity. For shy kids, let pairs build a story together. Keep stories short so the turn-taking stays brisk and no one tunes out.","safety":"Keep the activity seated and calm; this is a wind-down game, so set a quiet, listening-circle tone.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Rory's Story Cubes: How to Play","url":"https://www.youtube.com/watch?v=7XuZnWHDbNo"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/classroom-games/"}],"variations":["Chain version where each storyteller must continue the previous tale using their three new words.","Genre cards: draw a genre (scary, silly, mystery) along with the words."],"subsets":[["Let kids write some slips so they feel ownership of the word pool."],[],["Reassure storytellers that wild and silly is exactly the goal."],[],[],[]]},
  {"id":"gb-spelling-bee-relay","title":"Spell-It Relay","altNames":["Team Spelling Bee","Spell Down","Word Builder Relay"],"type":"Game","place":"Inside","ageMin":8,"ageMax":14,"durationMin":30,"groupMin":6,"groupMax":24,"energy":2,"prep":"Low","blurb":"Teams build words one letter at a time, each runner adding the next letter on the board, so spelling becomes a cheering, relay-paced team sport.","materials":["Whiteboard or large paper, two stations","Markers, assorted","Word list, prepared on slips","Boundary markers or tape, for start lines"],"materialTags":["Paper","Markers","Masking tape"],"steps":["Set up two writing stations a short distance from two team lines and place a word list face-down at each station.","The leader announces a word out loud (or reveals it on a card) that both teams must spell.","One runner from each team goes to the board and writes only the FIRST letter, then returns and tags the next teammate.","Teammates take turns adding one letter each until the word is complete; the first team to spell it correctly scores.","If a team finishes with a misspelling, they may send a runner to fix one letter before claiming the point.","Reset and announce a new word; rotate so everyone runs; highest score wins."],"notes":"Match word difficulty to the group's grade level. Walking instead of running keeps it safe indoors. Let teams quietly coach their runner on the next letter.","safety":"Require walking, not running, between line and board indoors, and keep the path clear of bags and chairs to prevent trips.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Spelling Bee Team Relay Game","url":"https://www.youtube.com/watch?v=S3z7qZRyCWM"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/classroom-games/"}],"variations":["Category words only (animals, foods) to add a brain twist.","Backwards relay where the word must be spelled last letter first."],"subsets":[["Make easy and hard word lists so you can match each group."],[],["Mark a single-file lane so runners don't collide passing each other."],[],[],[]]},
  {"id":"gb-guess-who-mystery-camper","title":"Guess the Mystery Camper","altNames":["Who Is It","Clue About a Friend","Secret Camper Reveal"],"type":"Game","place":"Both","ageMin":8,"ageMax":14,"durationMin":30,"groupMin":6,"groupMax":24,"energy":1,"prep":"None","blurb":"The leader reads three true clues about a secret camper in the room, and the group quietly figures out which smiling friend they're describing.","materials":["Paper, scrap for clue cards (optional)","Pencils or pens"],"materialTags":["Paper","No materials"],"steps":["Early in the session, have each camper secretly write two or three friendly facts about themselves on a slip (a hobby, a favorite food, a pet).","The leader collects the slips and shuffles them.","To play, the leader reads one slip's clues aloud one at a time, pausing between clues.","Campers silently raise a hand when they think they know who it is; the leader calls on someone after all clues are read.","Reveal the mystery camper, who can add one more fun fact, then move to the next slip.","Continue until many campers have been the happy mystery of the round."],"notes":"A wonderful name-learning and inclusion game for the first days of camp. Screen slips for kind, fun facts only. Read clues slowly to build suspense.","safety":"Keep clues positive and self-chosen; never let the game turn into pointing out appearances or teasing.","ages":["g13","g46","g79"],"rating":0,"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/classroom-games/"}],"variations":["Counselor edition where staff are the mystery people.","Two-clue lightning round once the group knows each other well."],"subsets":[["Give younger kids prompts: favorite animal, favorite color, something they're good at."],[],["Read the most unique clue last to keep guesses from coming too fast."],[],[],[]]},
  {"id":"gb-categories-pass-the-ball","title":"Beat the Beanbag Categories","altNames":["Hot Potato Categories","Pass and Name","List Race Toss"],"type":"Game","place":"Both","ageMin":7,"ageMax":13,"durationMin":30,"groupMin":6,"groupMax":20,"energy":2,"prep":"None","blurb":"Name a fruit before the beanbag reaches you, because once it's in your hands you have to fire off a fresh one or take the point.","materials":["Beanbag or soft ball, one","Timer or phone stopwatch, optional"],"materialTags":["Beanbag","No materials"],"steps":["Sit or stand in a circle; the leader announces a category like 'fruits,' 'sports,' or 'pizza toppings.'","Hand one player the beanbag; they must name an item in the category before passing it to a neighbor.","Each player who receives the beanbag must quickly name a NEW, non-repeated item, then pass it on.","If a player repeats an item, can't think of one within about 3 seconds, or names something off-category, they earn a strike.","After a few strikes a player steps out, or simply restart with a new category to keep everyone in.","Keep changing categories to stretch different kinds of knowledge."],"notes":"Choose broad categories for younger groups (animals, colors) and trickier ones for older kids (capital cities). Passing direction can reverse to keep alert.","safety":"Use a soft beanbag and toss gently to neighbors only, no whipping it across the circle at faces.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"How to Play the Hot Potato Game","url":"https://www.youtube.com/watch?v=KseTjh6W9aE"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/classroom-games/"}],"variations":["Reverse direction on a 'switch' call to keep brains alert.","Alphabet twist: each new item must start with the next letter of the alphabet."],"subsets":[["Keep a backup list of categories so there's never a lull."],[],["Allow a generous count for ages 7-8 before a strike."],[],[],[]]},
  {"id":"gb-guess-the-leader-mirror","title":"Spot the Secret Leader","altNames":["Guess the Leader","Follow the Leader Detective","Who's the Boss"],"type":"Game","place":"Both","ageMin":6,"ageMax":13,"durationMin":15,"groupMin":8,"groupMax":24,"energy":2,"prep":"None","blurb":"One detective steps out while the circle picks a secret leader whose every sneaky clap and toe-tap the whole group copies, and the detective must spot who's really in charge.","materials":["No materials needed"],"materialTags":["No materials"],"steps":["Everyone stands in a circle and one volunteer ('the detective') steps away and closes their eyes or faces out.","The group silently points to choose a secret leader, who will start small motions like clapping, tapping a knee, or nodding.","The leader begins a motion and everyone in the circle copies it; the detective returns to the center of the circle.","The leader keeps changing motions smoothly while the group follows, trying not to give away who is leading.","The detective watches and gets three guesses to name the secret leader.","If the detective guesses right, the leader becomes the next detective; if not, pick a new leader and detective and play again."],"notes":"Teach the group to glance at the leader using their eyes, not their heads, so they don't point the detective right at them. A fun low-prep transition game.","safety":"Keep the circle spacing wide enough that copied motions like stepping or swaying don't bump neighbors.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Game: Who's the Leader","url":"https://www.youtube.com/watch?v=VUbRbsZxsN0"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/classroom-games/"}],"variations":["Add sound (humming, stomping) for an extra-tricky version.","Two detectives work together for a faster-paced round."],"subsets":[[],["For young kids, whisper-assign the leader instead of silent pointing."],[],["Coach the leader to change motions every few seconds so it's not too easy."],[],[]]},
];
